/**
 * game.js — Main game loop, state machine, entity management
 */

// ── Canvas setup ─────────────────────────────────────────
const canvas = document.getElementById('game-canvas');
const ctx = canvas.getContext('2d');
const CANVAS_W = 800;
const CANVAS_H = 480;
canvas.width = CANVAS_W;
canvas.height = CANVAS_H;

// ── Responsive scaling ───────────────────────────────────
const container = document.getElementById('game-container');

function resizeCanvas() {
  const isMobile = Input.isMobile;
  if (isMobile) {
    // Scale to fit the screen while keeping aspect ratio
    const scale = Math.min(
      window.innerWidth / CANVAS_W,
      window.innerHeight / CANVAS_H
    );
    const w = CANVAS_W * scale;
    const h = CANVAS_H * scale;
    container.style.width = w + 'px';
    container.style.height = h + 'px';
    canvas.style.width = w + 'px';
    canvas.style.height = h + 'px';
  } else {
    container.style.width = CANVAS_W + 'px';
    container.style.height = CANVAS_H + 'px';
    canvas.style.width = CANVAS_W + 'px';
    canvas.style.height = CANVAS_H + 'px';
  }
}

resizeCanvas();
window.addEventListener('resize', resizeCanvas);

// ── Game state ───────────────────────────────────────────
let state = 'MENU'; // MENU | PLAYING | PAUSED | GAME_OVER | WIN | DYING
let map;
let player;
let enemies = [];
let coins = [];
let floatingItems = [];
let particles = [];
let score = 0;
let coinCount = 0;
let lives = 3;
let timeLeft = 400;
let timeAccum = 0;
let deathTimer = 0;
let winTimer = 0;
let flagReached = false;
let currentMapIndex = 0;
let warpTimer = 0;
let warpTargetMap = 0;
let warpTargetCol = 0;

// ── Init / Reset ─────────────────────────────────────────
function initGame() {
  currentMapIndex = 0;
  map = loadMap(currentMapIndex);
  player = new Player(3 * TILE, 11 * TILE);
  enemies = spawnEnemies().map(e => new Enemy(e.type, e.x, e.y));
  coins = spawnCoins().map(c => new Coin(c.x, c.y));
  floatingItems = [];
